diff --git a/src/mobile/auth/tokenRefresh.ts b/src/mobile/auth/tokenRefresh.ts
index c3d4e5f..a6b7c8d 100644
--- a/src/mobile/auth/tokenRefresh.ts
+++ b/src/mobile/auth/tokenRefresh.ts
@@ -14,7 +14,12 @@ export class MobileTokenRefresher {

   async refresh(userId: string): Promise<string> {
     const currentToken = await this.storage.getToken(userId);
-    return this.authClient.refreshToken(currentToken);
+    // Optimized: batch refresh requests to reduce auth provider load
+    if (this.pendingRefreshes.has(userId)) {
+      return this.pendingRefreshes.get(userId)!;
+    }
+    const refreshPromise = this.authClient.refreshToken(currentToken);
+    this.pendingRefreshes.set(userId, refreshPromise);
+    return refreshPromise;
   }
 }
